<!-- 功能说明
管理端内容管理核心页面，支持轮播海报的上传、预览、修改、排序、删除，设置海报跳转链接，
核心对接海报管理相关接口，支持拖拽排序优化用户操作体验�� -->�
<template>
  <view class="banner-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">海报管理</text>
      <button class="add-btn" @click="showAddModal">+ 新增海报</button>
    </view>

    <!-- 说明提示 -->
    <view class="tip-container">
      <text class="tip-text">温馨提示：海报尺寸建议为750*350px，最多上传8张，排序支持拖拽调整</text>
    </view>

    <!-- 海报列表（支持拖拽排序） -->
    <view class="banner-list" v-if="bannerList.length > 0">
      <draggable 
        v-model="bannerList"
        animation
        ghost-class="ghost"
        @start="onDragStart"
        @end="onDragEnd"
      >
        <view class="banner-item" v-for="(item, index) in bannerList" :key="item.id">
          <!-- 海报图片 -->
          <image :src="item.imageUrl" mode="aspectFill" class="banner-img"></image>
          
          <!-- 海报信息 -->
          <view class="banner-info">
            <text class="banner-title">{{item.title || '未命名海报'}}</text>
            <view class="link-info">
              <text class="link-label">跳转链接：</text>
              <text class="link-value">{{item.linkUrl || '无'}}</text>
            </view>
            <view class="status-tag" :class="item.status === 1 ? 'status-on' : 'status-off'">
              {{item.status === 1 ? '已启用' : '已禁用'}}
            </view>
          </view>
          
          <!-- 操作按钮 -->
          <view class="operation-group">
            <button class="oper-btn edit-btn" @click="showEditModal(item, index)">编辑</button>
            <button 
              class="oper-btn status-btn" 
              @click="toggleBannerStatus(item.id, item.status, index)"
            >
              {{item.status === 1 ? '禁用' : '启用'}}
            </button>
            <button class="oper-btn delete-btn" @click="deleteBanner(item.id, index)">删除</button>
          </view>
          
          <!-- 拖拽图标 -->
          <image src="../../static/images/icon-drag.png" class="drag-icon" @touchstart.prevent></image>
        </view>
      </draggable>
    </view>

    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/empty.png" class="empty-img"></image>
      <text class="empty-text">暂无海报数据，点击右上角新增</text>
    </view>

    <!-- 新增/编辑海报弹窗 -->
    <uni-modal 
      :title="isEditMode ? '编辑海报' : '新增海报'" 
      :visible="modalVisible" 
      width="90%"
      @confirm="confirmSubmit"
      @cancel="hideModal"
    >
      <view class="banner-form">
        <!-- 海报标题 -->
        <view class="form-item">
          <text class="form-label">海报标题：</text>
          <input 
            class="form-input" 
            v-model="formData.title" 
            placeholder="请输入海报标题（选填）"
            maxlength="50"
          ></input>
        </view>

        <!-- 海报图片上传 -->
        <view class="form-item">
          <text class="form-label required">海报图片：</text>
          <view class="upload-container">
            <view class="upload-preview" v-if="formData.imageUrl">
              <image :src="formData.imageUrl" mode="aspectFill" class="preview-img"></image>
              <image src="/static/images/icon-close.png" class="close-icon" @click="clearImage"></image>
            </view>
            <view class="upload-btn" @click="chooseImage" v-else>
              <image src="../../static/images/upload.png" class="upload-icon"></image>
              <text class="upload-text">点击上传海报图片</text>
            </view>
          </view>
          <text class="form-hint">建议尺寸：750*350px，支持jpg/png格式，单张不超过5MB</text>
        </view>

        <!-- 跳转链接 -->
        <view class="form-item">
          <text class="form-label">跳转链接：</text>
          <input 
            class="form-input" 
            v-model="formData.linkUrl" 
            placeholder="请输入跳转链接（如/product/detail?productId=123，选填）"
            maxlength="200"
          ></input>
          <text class="form-hint">支持内部页面路径或外部链接，为空则不跳转</text>
        </view>

        <!-- 启用状态 -->
        <view class="form-item status-item">
          <text class="form-label">启用状态：</text>
          <switch 
            :value="formData.status === 1" 
            active-color="#D4B886"
            inactive-color="#EEEEEE"
            @change="handleStatusChange"
          ></switch>
          <text class="status-text">{{formData.status === 1 ? '启用' : '禁用'}}</text>
        </view>
      </view>
    </uni-modal>
  </view>
</template>

<script setup>
import { ref, computed } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';

import { useUserStore } from '@/store/modules/userStore';
import request, { upload } from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const bannerList = ref([]); // 海报列表
const modalVisible = ref(false); // 弹窗显示状态
const isEditMode = ref(false); // 是否编辑模式
const formData = ref({
  id: '', // 海报ID（编辑模式）
  title: '', // 海报标题
  imageUrl: '', // 海报图片URL
  linkUrl: '', // 跳转链接
  status: 1 // 启用状态（1-启用，0-禁用）
});
const currentIndex = ref(-1); // 当前编辑索引
let dragStartIndex = -1; // 拖拽开始索引

// 页面加载时获取海报列表
onLoad(() => {
  if (!userStore.token || userStore.userInfo.role !== 'ADMIN') {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getBannerList();
});

onShow(() => {
  getBannerList();
});

// 接口请求：获取海报列表
const getBannerList = async () => {
  uni.showLoading({ title: '加载中' });
  try {
    const res = await request({
      url: '/api/admin/banner/list',
      method: 'GET'
    });
    if (res.success) {
      bannerList.value = res.data.sort((a, b) => a.sort - b.sort); // 按排序字段排序
    }
  } catch (error) {
    uni.showToast({ title: '海报列表加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 显示新增弹窗
const showAddModal = () => {
  isEditMode.value = false;
  formData.value = {
    id: '',
    title: '',
    imageUrl: '',
    linkUrl: '',
    status: 1
  };
  modalVisible.value = true;
};

// 显示编辑弹窗
const showEditModal = (item, index) => {
  isEditMode.value = true;
  currentIndex.value = index;
  formData.value = { ...item };
  modalVisible.value = true;
};

// 隐藏弹窗
const hideModal = () => {
  modalVisible.value = false;
  formData.value.imageUrl = ''; // 清空图片预览
};

// 选择并上传图片
const chooseImage = () => {
  uni.chooseImage({
    count: 1,
    sizeType: ['compressed'],
    sourceType: ['album', 'camera'],
    success: (res) => {
      const tempFilePath = res.tempFilePaths[0];
      uploadImage(tempFilePath);
    }
  });
};

// 上传图片接口
const uploadImage = async (filePath) => {
  uni.showLoading({ title: '图片上传中' });
  try {
    const res = await upload({
      url: '/api/upload/image',
      filePath: filePath,
      name: 'file',
      formData: {
        type: 'banner' // 图片类型标识
      }
    });
    if (res.success) {
      formData.value.imageUrl = res.data;
      uni.hideLoading();
    } else {
      uni.showToast({ title: res.message || '图片上传失败', icon: 'none' });
      uni.hideLoading();
    }
  } catch (error) {
    console.error('上传图片失败:', error);
  }
};

// 清空图片
const clearImage = () => {
  formData.value.imageUrl = '';
};

// 提交新增/编辑
const confirmSubmit = async () => {
  // 表单校验
  if (!formData.value.imageUrl) {
    uni.showToast({ title: '请上传海报图片', icon: 'none' });
    return;
  }

  uni.showLoading({ title: '提交中' });
  try {
    let res;
    if (isEditMode.value) {
      // 编辑海报
      res = await request({
        url: '/api/admin/banner/update',
        method: 'PUT',
        data: formData.value
      });
    } else {
      // 新增海报
      res = await request({
        url: '/api/admin/banner/add',
        method: 'POST',
        data: {
          ...formData.value,
          sort: bannerList.value.length + 1 // 新增海报排序在最后
        }
      });
    }

    if (res.success) {
      uni.showToast({ title: isEditMode.value ? '编辑成功' : '新增成功' });
      hideModal();
      getBannerList();
    } else {
      uni.showToast({ title: res.message || (isEditMode.value ? '编辑失败' : '新增失败'), icon: 'none' });
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 处理开关状态变化
const handleStatusChange = (event) => {
  formData.value.status = event.detail.value ? 1 : 0;
};

// 切换海报启用状态
const toggleBannerStatus = async (bannerId, status, index) => {
  const newStatus = status === 1 ? 0 : 1;
  const statusText = newStatus === 1 ? '启用' : '禁用';

  uni.showModal({
    title: '提示',
    content: `确定要${statusText}该海报吗？`,
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/banner/updateStatus',
            method: 'PUT',
            data: { id: bannerId, status: newStatus }
          });
          if (res.success) {
            uni.showToast({ title: `${statusText}成功` });
            bannerList.value[index].status = newStatus;
          } else {
            uni.showToast({ title: `${statusText}失败`, icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 删除海报
const deleteBanner = async (bannerId, index) => {
  uni.showModal({
    title: '警告',
    content: '确定要删除该海报吗？删除后不可恢复！',
    confirmColor: '#F53F3F',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/banner/delete',
            method: 'DELETE',
            data: { bannerId }
          });
          if (res.success) {
            uni.showToast({ title: '删除成功' });
            bannerList.value.splice(index, 1);
            // 更新排序
            updateBannerSort();
          } else {
            uni.showToast({ title: '删除失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，删除失败', icon: 'none' });
        }
      }
    }
  });
};

// 拖拽开始
const onDragStart = (e) => {
  dragStartIndex = e.index;
};

// 拖拽结束
const onDragEnd = (e) => {
  if (dragStartIndex !== e.index) {
    // 更新排序
    updateBannerSort();
  }
};

// 更新海报排序
const updateBannerSort = async () => {
  const sortData = bannerList.value.map((item, index) => ({
    id: item.id,
    sort: index + 1 // 排序从1开始
  }));

  try {
    await request({
      url: '/api/admin/banner/updateSort',
      method: 'PUT',
      data: { sortList: sortData }
    });
  } catch (error) {
    console.log('排序更新失败', error);
    // 排序更新失败时重新获取列表，恢复原有排序
    getBannerList();
  }
};
</script>

